import YAML from 'yaml'

export function parseYml(yml = ''): Record<string, any> {
  try {
    return YAML.parse(yml, {
      prettyErrors: true,
      schema: 'core',
      version: '1.2',
    })
  } catch (error) {
    console.error(error)
    return {}
  }
}

export function toYml(obj: any) {
  return YAML.stringify(obj, {
    prettyErrors: true,
    schema: 'core',
    version: '1.2',
  })
}
