export default {
  /**
   * @function
   * @description Returns a random number between 0 (inclusive) and 1 (exclusive)
   * @param {void}
   * @returns {number}
   * 
   */
  random: function () {
    const rand = Math.random()
    return rand
  },
  /**
   * @function
   * @description Returns the Sum of two numbers
   * @param {number} num1
   * @param {number} num2
   * @returns {number}
   * 
   */
  add: function ({ num1, num2 }: { num1: number, num2: number }): number {
    return num1 + num2
  },
  /**
   * @function
   * @description Judge the relationship between two numbers
   * @param {number} num1
   * @param {number} num2
   * @returns {boolean}
   * 
   */
  greater: function ({ num1, num2 }: { num1: number, num2: number }): boolean {
    return num1 >= num2
  },
  /**
   * @function
   * @description Whether the folder size exceeds the judgment
   * @param {number} object
   * @param {number} key
   * @returns {boolean}
   * 
   */
  lessthanSize: function ({ object, key }: { object: {}, key: number }): boolean {
    let objectSize: string = object['size']
    if (parseFloat(objectSize).toString() !== "NaN") {
      let maxSize: number = Math.floor(key * Math.pow(1024, 2))
      return parseFloat(objectSize) > maxSize ? false : true
    }
    return false
  },
  cumulative: function ({ numArr }: { numArr: [] }): number {
    let total = 0
    for (let i = 0; i < numArr.length; i++) {
      total = total + parseInt(numArr[i])
    }
    return total
  },
  toFixedNum({num}:{num: number|string}) {

    console.log( (+num).toFixed(2))
    return (+num).toFixed(2);

  },
  FixedLimit({num}:{num: number|string}):boolean {


    return (String(num).length - String(num).indexOf(".") - 1 === 2) ? true : false;

  }
}
