import cloneDeep from 'lodash/cloneDeep'
import type { CommonTypes } from '../../common/ecos'
import store from '../../common/store'
import replaceEidWithId from '../../utils/replaceEidWithId'
import { UnableToLocateValue } from '../../errors'
import isPopulated from '../../utils/isPopulated'
import mergeDeep from '../../utils/mergeDeep'
import * as c from '../../constants'

export { get, create }

/**
 *
 * @param output Api object
 */
function get({ pageName, apiObject, dispatch }) {
  return async function sendRetrieveEdge() {
    let res = {} as {
      error?: {
        code: number
        name: string
        message: string
        source?: string
      }
      jwt: null | string
      edge: null | string | CommonTypes.Edge[]
      code: number
    }

    let idList: string[] | Uint8Array[] = []

    const { api, dataKey, dataIn, dataOut, ...options } = cloneDeep(
      apiObject || {},
    )
    let requestOptions = { ...options }
    let maxcount = options?.maxcount
    let type = options?.type
    let sCondition = options?.sCondition
    let nonce: number | null = null

    // Get current object name value
    const currentVal = await dispatch({
      type: c.dispatchActionType.GET_DATA,
      payload: { pageName, dataKey: dataIn || dataKey },
    })

    if (dataIn) {
      const { deat, id, _nonce, ...populatedCurrentVal } = await dispatch({
        type: c.dispatchActionType.POPULATE_OBJECT,
        payload: { object: currentVal, pageName, copy: true },
      })

      nonce = _nonce

      if (!isPopulated(id)) {
        const err = new UnableToLocateValue(
          `Missing reference ${id} at page ${pageName}`,
        )
        return console.error(err)
      }
      idList = Array.isArray(id) ? [...id] : [id]

      requestOptions = { ...requestOptions, ...populatedCurrentVal }
      maxcount = populatedCurrentVal?.maxcount
      type = populatedCurrentVal?.type
      sCondition = populatedCurrentVal?.sCondition
    } else if (options.id) {
      idList = Array.isArray(options.id) ? [...options.id] : [options.id]
    }
    const { deat, id, _nonce, ...populatedCurrentVal } = await dispatch({
      type: c.dispatchActionType.POPULATE_OBJECT,
      payload: { object: requestOptions, pageName },
    })
    requestOptions = { ...requestOptions, ...populatedCurrentVal }

    if (maxcount) {
      requestOptions.maxcount = parseInt(maxcount)
    }
    if (type) {
      requestOptions.type = parseInt(type)
    }
    if (sCondition) {
      requestOptions.scondition = sCondition
    }
    //Buffer check
    const { pass: shouldPass, cacheIndex } = await dispatch({
      type: c.dispatchActionType.SET_API_BUFFER,
      payload: {
        apiObject: {
          idList,
          options: requestOptions,
          nonce,
        },
      },
    })
    try {
      if (store.env === 'test') {
        console.log(
          '%cGet Edge Request',
          'background: purple; color: white; display: block;',
          {
            idList,
            options: requestOptions,
          },
        )
      }

      // idList?.forEach?.((id) => {
      //   // if (!id) debugger
      // })

      if (!shouldPass) {
        res = await dispatch({
          type: c.dispatchActionType.GET_CACHE,
          payload: { cacheIndex },
        })
        if (store.env === 'test') {
          console.log(
            `%cUsing Cached Data for`,
            'background:#7268A6; color: white; display: block;',
            apiObject,
          )
        }
        //
      } else {
        const { data } = await store.level2SDK.edgeServices.retrieveEdge({
          //@ts-expect-error
          idList: idList?.filter?.(Boolean) || [],
          options: requestOptions,
        })
        await dispatch({
          type: c.dispatchActionType.SET_CACHE,
          payload: { data, cacheIndex },
        })
        res = data
      }
    } catch (error) {
      throw error
    }

    //Doesn't update the state. Shows mock data instead.
    if (!res?.edge?.length && store.env === 'test') {
      console.log(
        '%cGet Edge Response',
        'background: purple; color: white; display: block;',
        res,
      )
      if (res.error) {
        if (
          res.error.name == 'REQUIRED_PHONE_NUMBER_AND_VERIFICATION_CODE' ||
          res.error.code == 1005
        ) {
          //
        }
      }
    } else {
      //maps edge.eid to edge.id
      let listOfEdgesWithId = (
        Array.isArray(res?.edge) ? res?.edge : [res?.edge]
      )
        .map((edge) => {
          return replaceEidWithId(edge)
        })
        .filter(Boolean)
      res.edge = listOfEdgesWithId as any
      if (store.env === 'test') {
        console.log(
          '%cGet Edge Response',
          'background: purple; color: white; display: block;',
          res,
        )
      }
      if (res.jwt) {
        //update Global jwt
        await dispatch({
          type: c.dispatchActionType.UPDATE_DATA,

          payload: {
            dataKey: 'Global.currentUser.JWT',
            data: res.jwt,
          },
        })
      }
      await dispatch({
        type: c.dispatchActionType.UPDATE_DATA,
        //TODO: handle case for data is an array or an object
        payload: {
          pageName,
          dataKey: dataOut ? dataOut : dataKey,
          data: res,
        },
      })
    }

    return res
  }
}

/**
 * Creates an edge or updates an edge if there is an id
 * in the apiObject
 *
 * @param param0
 */
function create({ pageName, apiObject, dispatch }) {
  return async function sendCreateEdge(name) {
    const { dataKey, dataIn, dataOut } = cloneDeep(apiObject || {})

    // Get current object name value
    const { deat, id, ...rest } = await dispatch({
      type: c.dispatchActionType.GET_DATA,
      payload: { pageName, dataKey: dataIn || dataKey },
    })

    let obj = await dispatch({
      type: c.dispatchActionType.POPULATE_OBJECT,
      payload: { object: rest, pageName, copy: true },
    })

    const isFCMRegisterEdge = obj.type === 1090

    if (isFCMRegisterEdge) obj.subtype = 2

    if (!isPopulated(id)) {
      throw new UnableToLocateValue(
        `Missing reference ${id} at page ${pageName}`,
      )
    }
    //merging existing name field and incoming name field
    const parsedType = parseInt(obj.type)
    let res: any

    if (Number.isNaN(parsedType) || parsedType === 0) return
    obj = { ...obj, type: parsedType }
    name && (obj = mergeDeep(obj, { name }))
    //if there is an id present
    //it is treated as un update request
    if (id && !id.startsWith('.')) {
      try {
        if (store.env === 'test') {
          console.log(
            '%cUpdate Edge Request',
            'background: purple; color: white; display: block;',
            { ...obj, id },
          )
        }

        const { data } = await store.level2SDK.edgeServices.updateEdge({
          ...obj,
          id,
        })
        res = data

        if (store.env === 'test') {
          console.log(
            '%cUpdate Edge Response',
            'background: purple; color: white; display: block;',
            res,
          )
        }
      } catch (error) {
        throw error
      }
    } else {
      try {
        if (store.env === 'test') {
          console.log(
            '%cCreate Edge Request',
            'background: purple; color: white; display: block;',
            obj,
          )
        }
        const { data } = await store.level2SDK.edgeServices.createEdge(obj)
        const isInviteEdge = data?.edge?.type === 1053
        if (isInviteEdge) {
          const pkOfInviter = localStorage.getItem('pk')
          const skOfInviter = localStorage.getItem('sk')
          const {
            data: { edge },
          } = await store.level2SDK.edgeServices.retrieveEdge({
            idList: [data?.edge?.refid],
          })
          const rootEdge = edge[0]
          let rootEdgeBesak = rootEdge?.besak
          if (!rootEdge?.besak) {
            const besak =
              store.level2SDK.commonServices.generateEsak(pkOfInviter)
            const { data: updatedRootEdgeRes } =
              await store.level2SDK.edgeServices.updateEdge({
                id: rootEdge.eid,
                type: 40000,
                besak,
                name: rootEdge.name,
              })

            if (updatedRootEdgeRes?.edge) rootEdgeBesak = besak
          }
          let pkOfInviterToUint8Array, skOfInviterToUint8Array
          if (pkOfInviter && skOfInviter) {
            pkOfInviterToUint8Array =
              store.level2SDK.utilServices.base64ToUint8Array(pkOfInviter)
            skOfInviterToUint8Array =
              store.level2SDK.utilServices.base64ToUint8Array(skOfInviter)
          }
          const sak = store.level2SDK.utilServices.aKeyDecrypt(
            pkOfInviterToUint8Array,
            skOfInviterToUint8Array,
            rootEdgeBesak,
          )
          const inviteEdge = data?.edge
          const pkOfInvitee = inviteEdge.deat.evPK
            ? inviteEdge.deat.evPK
            : inviteEdge.deat.eePK
          const pkOfInviteeToUint8Array =
            store.level2SDK.utilServices.base64ToUint8Array(pkOfInvitee)
          if (sak) {
            const eesak = store.level2SDK.utilServices.aKeyEncrypt(
              pkOfInviteeToUint8Array,
              skOfInviterToUint8Array,
              sak,
            )
            const { data: updatedInviteEdgeRes } =
              await store.level2SDK.edgeServices.updateEdge({
                id: inviteEdge.eid,
                type: 1053,
                eesak,
                name: inviteEdge.name,
              })
            res = updatedInviteEdgeRes
          }
        } else {
          res = data
        }

        if (store.env === 'test') {
          console.log(
            '%cCreate Edge Response',
            'background: purple; color: white; display: block;',
            res,
          )
        }
      } catch (error) {
        throw error
      }
    }

    if (res) {
      res.edge = replaceEidWithId(res.edge)

      if (res.jwt) {
        // Update Global jwt
        await dispatch({
          type: c.dispatchActionType.UPDATE_DATA,
          payload: { dataKey: 'Global.currentUser.JWT', data: res.jwt },
        })
      }

      await dispatch({
        type: c.dispatchActionType.UPDATE_DATA,
        //TODO: handle case for data is an array or an object
        payload: {
          pageName,
          dataKey: dataOut || dataKey,
          data: res,
        },
      })

      // Dispatch action to update state that is dependant of this response
      await dispatch({
        type: c.dispatchActionType.POPULATE,
        payload: { pageName },
      })
    }
    return res
  }
}
