/**
 * Merges keys in source object with objects in locations where keys match lookFor.
 *
 * @param PopulateKeysArgs
 * @param PopulateKeysArgs.source Object to populate.
 * @param PopulateKeysArgs.lookFor Symbols to lookFor in properties e.g ['..,.']
 * @param PopulateKeysArgs.locations
 * @returns Populated object.
 */
function populateKeys({
  source,
  lookFor,
  locations,
}: {
  source: Record<string, any>
  lookFor: string
  locations: Record<string, any>[]
}): Record<string, any> {
  let output = source

  Object.keys(output).forEach((key) => {
    if (key.startsWith(lookFor)) {
      let parent = {}
      let currKey = key

      if (lookFor === '..') {
        currKey = currKey.slice(1)
      }

      for (let location of locations) {
        try {
          let arr = currKey.split('.')
          let res: any

          try {
            res = arr.slice(1).reduce((o, key) => o[key], location)
          } catch (error) {
            throw new UnableToLocateValue(
              'Value not found',
              error instanceof Error ? error : new Error(String(error)),
            )
          }
          // NOTE: This block is only entered for root references
          if (res) parent = cloneDeep(res)
        } catch (error) {
          if (error instanceof UnableToLocateValue) continue
          else throw error
        }
      }

      if (u.keys(parent).length && output[key]) {
        const mergedObjects = mergeDeep(
          populateKeys({ source: parent, lookFor, locations: [...locations] }),
          populateKeys({
            source: output[key],
            lookFor,
            locations: [...locations],
          }),
        )
        output = { ...output, ...mergedObjects }
        delete output[key]
      } else if (u.keys(parent).length) {
        // TODO: test why it is undefined when .Edge:""
        // Check SignUp page
        delete parent[key]
        const mergedObjects = populateKeys({
          source: parent,
          lookFor,
          locations,
        })
        output = mergeDeep(mergedObjects, output)
        delete output[key]
      }
    } else if (u.isObj(output[key])) {
      output[key] = populateKeys({
        source: output[key],
        lookFor,
        locations: [...locations],
      })
    } else if (u.isArr(output[key])) {
      const copy = [...output[key]]
      output[key].length = 0
      for (let item of copy) {
        if (u.isObj(item)) {
          item = populateKeys({
            source: item,
            lookFor,
            locations: [...locations],
          })
        }
        output[key].push(item)
      }
    }
  })
  return output
}

/**
 * Attaches ecos functions to api objects.
 *
 * There are two kinds of API objects.
 *
 * There are objects who have an "api" property where the value is an eCOS method
 *
 * @example
 * ```
 * const apiObject = { api: 'ce', dataIn: {...}, dataOut: {...} }
 * ```
 *
 * And there are objects who are references to builtIn functions
 *
 * @example
 *
 * ```
 * const builtInReference = {
 * 	'=.builtIn.string.equal': {
 *			dataIn: {...},
 *			dataOut: {...}
 *   }
 * }
 * ```
 *
 * @param cadlObject
 * @param dispatch
 * @returns The object with functions attached to it.
 */
function createFuncAttacher({
  cadlObject,
  dispatch,
  force = false,
}: {
  cadlObject: Record<string, any>
  dispatch: CADL['dispatch']
  force?: boolean
}): Record<string, any> {
  let keys = u.keys(cadlObject)
  let pageName = keys.length > 1 ? 'Global' : keys[0]

  return attachFnsHelper({
    pageName,
    cadlObject,
    dispatch,
    force,
  })

  function attachFnsHelper({
    pageName,
    cadlObject,
    dispatch,
    force = false,
  }: {
    pageName: string
    cadlObject: Record<string, any>
    dispatch: Function
    force?: boolean
  }): Record<string, any> {
    // Traverse through the page object and look for the api keyword
    let output = cadlObject
    if (pageName === 'Global' && !force) return output

    if (u.isObj(output)) {
      u.keys(output).forEach((key) => {
        if (u.isObj(output[key])) {
          output[key] = attachFnsHelper({
            pageName,
            cadlObject: output[key],
            dispatch,
          })
        } else if (u.isArr(output[key])) {
          const copy = [...output[key]]
          output[key].length = 0
          for (let item of copy) {
            if (u.isObj(item)) {
              item = attachFnsHelper({ pageName, cadlObject: item, dispatch })
            }
            output[key].push(item)
          }
        } else if (u.isStr(output[key]) && key === 'api') {
          const pathToNameField = `${output.dataOut || output.dataKey}.name`
          // When api keyword is found we attach the ecos function
          const { api, _nonce, ...restOptions } = output
          // Have this because api can be of shape 'builtIn.***'
          const apiSplit = api.split('.')
          const apiType = apiSplit[0]
          const apiFunc = services(apiType)({
            pageName,
            apiObject: output,
            dispatch,
          })

          if (/(ce|cd|cv|builtIn)/.test(apiType)) {
            if (isPopulated(output)) output = [pathToNameField, apiFunc]
          } else {
            if (isPopulated(restOptions)) {
              const args = { pageName, apiObject: output, dispatch }
              output = services(apiType)(args)
            }
          }
        }
      })
    }

    return output
  }
}

export const createFuncAttacher2 = (function () {
  const fns = {
    ce: edgeServices.create,
    re: edgeServices.get,
    cv: vertexServices.create,
    rv: vertexServices.get,
    cd: documentServices.create,
    rd: documentServices.get,
    dx: remove.remove,
    builtIn: builtInServices.builtIn,
  }

  function getPageName(obj: Record<string, any>) {
    const keys = u.keys(obj)
    return keys.length > 1 ? 'Global' : keys[0]
  }

  const isApiKeyPair = (key = '', value: any) => u.isStr(value) && key === 'api'

  function hashParams(obj) {
    return `${obj.dataOut || obj.dataKey}.name`
  }

  const cache = {
    prepare: {},
  } as Record<string, any>

  function attach({
    pageName = '',
    cadlObject,
    dispatch,
    force = false,
  }: {
    pageName: string
    cadlObject: Record<string, any>
    dispatch: CADL['dispatch']
    force?: boolean
  }) {
    // Traverse through the page object and look for the api keyword
    let output = cadlObject
    if (pageName === 'Global' && !force) return output

    if (u.isObj(output)) {
      for (const [key, value] of u.entries(output)) {
        // Attach the ecos request function
        if (isApiKeyPair(key, value)) {
          const pathToNameField = hashParams(output)

          // param1 = json arr
          // param2 = name list / common seperated properteis (picked from the obj)

          if (!cache[pathToNameField]) {
            cache[pathToNameField] = isPopulated(output)
              ? [
                  pathToNameField,
                  fns[value]({ pageName, apiObject: output, dispatch }),
                ]
              : // @ts-expect-error
                fns[api]({ pageName, apiObject: output, dispatch })

            if (/(ce|cd|cv|builtIn)/.test(value)) {
              // @ts-expect-error
              if (isPopulated(output)) output = [pathToNameField, apiFunc]
            } else {
              // @ts-expect-error
              if (isPopulated(restOptions)) {
                // @ts-expect-error
                output = fns[api]({ pageName, apiObject: output, dispatch })
              }
            }
          }

          const { api, _nonce, ...restOptions } = output
          const apiFunc = fns[api]({ pageName, apiObject: output, dispatch })

          if (/(ce|cd|cv|builtIn)/.test(api)) {
            if (isPopulated(output)) output = [pathToNameField, apiFunc]
          } else {
            if (isPopulated(restOptions)) {
              output = fns[api]({ pageName, apiObject: output, dispatch })
            }
          }
          continue
        }

        if (u.isArr(value) || u.isObj(value)) {
          attach({ pageName, cadlObject: value, dispatch })
        }
      }
    } else if (u.isArr(output)) {
      u.forEach((o) => attach({ pageName, cadlObject: o, dispatch }), output)
    }

    return output
  }

  function attachFns({
    cadlObject,
    dispatch,
    force = false,
  }: {
    cadlObject: Record<string, any>
    dispatch: CADL['dispatch']
    force?: boolean
  }): Record<string, any> {
    const pageName = getPageName(cadlObject)
    return attach({
      pageName,
      cadlObject,
      dispatch,
      force,
    })
  }

  return attachFns
})()

/**
 * Returns a function that is used to evalutate actionType evalObject.
 *
 * @param EvalStateArgs
 * @param EvalStateArgs.pageName
 * @param EvalStateArgs.updateObject
 * @param EvalStateArgs.dispatch
 * @returns Function that runs the series of operations detailed in the updateObject.
 *
 */
function evalState({
  pageName,
  updateObject,
  dispatch,
}: {
  pageName: string
  updateObject: Record<string, any>
  dispatch: Function
}): Function {
  async function onEvalState(a): Promise<void> {
    // REMINDER: evalObject (with actionType key) can be the result here
    // Another: '+1 8882465555'
    return dispatch({
      type: c.dispatchActionType.EVAL_OBJECT,
      payload: { pageName: a.pageName, updateObject: a.updateObject },
    })
  }

  // @ts-expect-error
  return onEvalState.bind(this, {
    pageName,
    updateObject,
    dispatch,
  })
}

/**
 * Replaces the eval object, if any, with a function that performs the the actions detailed in the actionType evalObject
 *
 * @param ReplaceEvalObjectArgs
 * @param ReplaceEvalObjectArgs.cadlObject
 * @param ReplaceEvalObjectArgs.dispatch
 * @returns Object with evalObject replaced by a function.
 *
 */
async function replaceEvalObject({
  pageName,
  cadlObject,
  dispatch,
}: {
  pageName: string
  cadlObject: Record<string, any>
  dispatch: Function
}): Promise<Record<string, any>> {
  const cadlCopy = cadlObject
  if (
    u.isObj(cadlObject) &&
    ('emit' in cadlObject || 'actions' in cadlObject)
  ) {
    // console.log(`[replaceEvalObject] cadlObject`, cadlObject)
    // debugger
  }

  for (const key of u.keys(cadlCopy)) {
    if (key === 'object' && nt.Identify.action.evalObject(cadlCopy)) {
      const updateObject = cloneDeep(cadlCopy[key]) as Record<string, any>
      cadlCopy[key] = evalState({ pageName, updateObject, dispatch }) as any

      // Used to update global state after user signin
      if (
        pageName === 'SignIn' ||
        pageName === 'CreateNewAccount' ||
        pageName === 'SignUp'
      ) {
        await dispatch({
          type: c.dispatchActionType.ADD_FUNCTION,
          payload: {
            pageName,
            fn: evalState({ pageName, updateObject, dispatch }),
          },
        })
      }
    } else if (u.isObj(cadlCopy[key])) {
      cadlCopy[key] = await replaceEvalObject({
        pageName,
        cadlObject: cadlCopy[key],
        dispatch,
      })
    } else if (u.isArr(cadlCopy[key])) {
      const currentLength = cadlCopy[key].length
      for (let index = 0; index < currentLength; index++) {
        cadlCopy[key][index] = await replaceEvalObject({
          pageName,
          cadlObject: cadlCopy[key][index],
          dispatch,
        })
      }
    }
  }
  return cadlCopy
}

/**
 * Used to de-reference a string by looking for value in locations.
 * @param PopulateStringArgs
 * @param PopulateStringArgs.source Object that has values that need to be replaced
 * @param PopulateStringArgs.lookFor Item to look for in object
 * @param PopulateStringArgs.locations Array of objects that may contain the values for the source object
 * @param PopulateStringArgs.path The path to the value that will be changed.
 * @param PopulateStringArgs.dispatch Function to change the state.
 * @param PopulateStringArgs.pageName
 *
 * @returns De-referenced object.
 */
function populateString({
  source,
  lookFor,
  skip,
  locations = [],
  path,
  dispatch,
  pageName,
}: {
  source: string
  lookFor: string
  skip?: string[]
  locations: Record<string, any>[]
  path?: string[]
  dispatch?: Function
  pageName?: string
}) {
  if (skip && skip.includes(source)) return source
  if (!source.startsWith(lookFor)) return source

  let currVal = source
  let replacement: any

  if (lookFor === '~') {
    currVal = '.myBaseUrl'
  } else if (lookFor === '_' && currVal.includes('.')) {
    let charArr = currVal.split('')
    let copyPath = clone(path) || []
    let currChar = charArr.shift()

    while (currChar !== '.' && charArr.length > 0) {
      if (currChar === '_') copyPath.pop()
      currChar = charArr.shift()
    }

    replacement = '.' + copyPath.concat(charArr.join('')).join('.')
    // NOTE: This is intentionally returning a referenced string, so this is not actually resolved yet and it is up to the caller to resolve this
    return replacement
  } else if (lookFor === '..') {
    currVal = currVal.slice(1)
  } else if (lookFor === '=') {
    if (source.startsWith('=..')) currVal = currVal.slice(2)
    else if (source.startsWith('=.')) currVal = currVal.slice(1)
  }

  if (currVal.startsWith('.')) currVal = currVal.slice(1)
  if (currVal.startsWith('$')) currVal = currVal.slice(1)

  for (let location of locations) {
    try {
      replacement = dot.pick(currVal, location)

      // Defaults to baseUrl if myBaseUrl is not available
      if (currVal === '.myBaseUrl' && !replacement) {
        replacement = dot.pick('.baseUrl', location)
      }
      if (replacement && lookFor == '~') {
        replacement = replacement + source.substring(2)
        break
      } else if (
        (replacement || replacement === '' || replacement === 0) &&
        replacement !== source
      ) {
        if (u.isStr(replacement) && replacement.startsWith(lookFor)) {
          return populateString({
            source: replacement,
            lookFor,
            skip,
            locations: [...locations],
            path,
            pageName,
            dispatch,
          })
        } else {
          break
        }
      }
    } catch (error) {
      if (error instanceof UnableToLocateValue) continue
      else throw error
    }
  }

  if (!u.isUnd(replacement) && replacement !== source) {
    return replacement
  }
  if (!!isPopulated(source)) {
    if (!_TEST_ && store.env === 'test' && path) {
      console.log(
        `%cReference Not Found in ${pageName}`,
        'background: orange; color: black; display: block;',
        { [path.join('.')]: source },
      )
    }
  }
  return source
}

/**
 * Dereference values in an array data structure.
 *
 * @param PopulateArrayArgs
 * @param PopulateArrayArgs.source Object that has values that need to be replaced.
 * @param PopulateArrayArgs.lookFor Item to look for in object
 * @param PopulateArrayArgs.locations Array of objects that may contain the values for the source object
 * @param PopulateArrayArgs.path
 * @param PopulateArrayArgs.dispatch Function to change the state.
 * @param PopulateArrayArgs.pageName
 *
 * @returns Dereferenced array.
 */
function populateArray({
  source,
  lookFor,
  skip,
  locations,
  path,
  dispatch,
  pageName,
  skipIf = true,
}: {
  source: any[]
  lookFor: string
  skip?: string[]
  locations: Record<string, any>[]
  path?: string[]
  dispatch?: Function
  pageName?: string
  skipIf?: boolean
}): any[] {
  let sourceCopy = source
  if (path) {
    var previousKey = path[path.length - 1] || ''
  }
  const copy = [...sourceCopy]
  sourceCopy.length = 0
  let replacement = copy.reduce((acc, elem, i) => {
    let index = '[' + i + ']'
    if (u.isArr(elem)) {
      elem = populateArray({
        source: elem,
        skip,
        lookFor,
        locations: [...locations],
        path: path?.slice(0, -1).concat(previousKey + index),
        dispatch,
        pageName,
        skipIf,
      })
    } else if (u.isObj(elem)) {
      if (
        !(
          ('actionType' in elem &&
            elem.actionType === 'evalObject' &&
            elem.object &&
            u.isObj(elem.object)) ||
          u.isArr(elem.object)
        )
      ) {
        elem = populateObject({
          source: elem,
          skip,
          lookFor,
          locations: [...locations],
          path: path?.slice(0, -1).concat(previousKey + index),
          dispatch,
          pageName,
          skipIf,
        })
      }
    } else if (typeof elem === 'string') {
      elem = populateString({
        source: elem,
        skip,
        lookFor,
        locations: [...locations],
        path: path?.slice(0, -1).concat(previousKey + index),
        dispatch,
        pageName,
      })
    }
    acc.push(elem)
    return acc
  }, [])
  sourceCopy.push(...replacement)
  copy.length = 0
  return sourceCopy
}

/**
 * De-references source object by looking for items in the given locations.
 *
 * @param PopulateObjectArgs
 * @param PopulateObjectArgs.source Object that has values that need to be replaced
 * @param PopulateObjectArgs.lookFor Item to look for in object
 * @param PopulateObjectArgs.locations Array of objects that may contain the values for the source object
 * @param PopulateObjectArgs.skip
 * @param PopulateObjectArgs.path
 * @param PopulateObjectArgs.dispatch
 * @param PopulateObjectArgs.pageName
 *
 * @returns Dereferenced object
 */
function populateObject({
  source = {},
  lookFor,
  locations,
  skip = [],
  path = [],
  dispatch,
  pageName,
  skipIf = true,
}: {
  source: Record<string, any>
  lookFor: string
  locations: Record<string, any>[]
  skip?: string[]
  path?: string[]
  dispatch?: Function
  pageName?: string
  skipIf?: boolean
}): Record<string, any> {
  let sourceCopy = source

  if ('emit' in sourceCopy || 'actions' in sourceCopy) {
    // console.log(`[replaceEvalObject] cadlObject`, arguments[0])
    // debugger
  }

  for (const key of u.keys(sourceCopy)) {
    let index = key
    let isBuiltIn = key.includes('builtIn')
    let shouldSkipIf = false
    let shouldSkipBuiltIn = false

    key === 'if' && skipIf && (shouldSkipIf = true)
    isBuiltIn && skip.includes('builtIn') && (shouldSkipBuiltIn = true)

    if (
      key !== 'dataKey' &&
      !skip.includes(key) &&
      !shouldSkipIf &&
      !shouldSkipBuiltIn
    ) {
      const options = {
        source: sourceCopy[key],
        skip,
        lookFor,
        path: path.concat(index),
        dispatch,
        pageName,
      }

      if (u.isObj(sourceCopy[key])) {
        if (
          !(
            nt.Identify.action.evalObject(sourceCopy[key]) &&
            u.isObj(sourceCopy[key].object)
          ) ||
          u.isArr(sourceCopy[key]?.object)
        ) {
          sourceCopy[key] = populateObject({
            ...options,
            locations: [...locations],
            skipIf,
          })
        }
      } else if (u.isArr(sourceCopy[key])) {
        sourceCopy[key] = populateArray({
          ...options,
          locations: [...locations],
          skipIf,
        })
      } else if (u.isStr(sourceCopy[key])) {
        if (nt.Identify.reference(key) && !key.startsWith('=.builtIn')) {
          if (!hasPropertyDescriptor(sourceCopy, key)) {
            const obj = sourceCopy
            const value = obj[key]
            const options = {
              dispatch,
              locations: [...locations],
              lookFor,
              pageName,
              path: path.concat(index),
              source: value,
              skip,
            }

            const getter = () => {
              return populateString(options)
            }

            defineProperty(obj, key, getter)
          }
        } else {
          sourceCopy[key] = populateString({
            dispatch,
            locations: [...locations],
            lookFor,
            pageName,
            path: path.concat(index),
            source: sourceCopy[key],
            skip,
          })
        }
      }
    }
  }

  return sourceCopy
}

/**
 * De-reference source object by looking for multiple items in multiple locations.
 *
 * @param PopulateValsArgs
 * @param PopulateValsArgs.source Object that needs de-referencing.
 * @param PopulateValsArgs.lookFor An array of items to look for e.g ['.','..']
 * @param PopulateValsArgs.locations Locations to look for values.
 * @param PopulateValsArgs.skip Keys to skip in the de-referencing process.
 * @param PopulateValsArgs.pageName
 * @param PopulateValsArgs.dispatch Function to alter the state.
 * @returns
 */
function populateVals({
  source,
  lookFor,
  locations,
  skip,
  pageName,
  dispatch,
}: {
  source: Record<string, any> | string
  lookFor: string[]
  skip?: string[]
  locations: any[]
  pageName?: string
  dispatch?: Function
}): any {
  let sourceCopy = source

  for (let symbol of lookFor) {
    sourceCopy = (u.isStr(sourceCopy) ? populateString : populateObject)({
      // @ts-expect-error
      source: sourceCopy,
      lookFor: symbol,
      skip,
      locations: [...locations],
      pageName,
      dispatch,
    })
  }

  return sourceCopy
}

/**
 * Replaces Uint8Array values with base64 values
 *
 * @param source Object that needs values replaced.
 * @returns Object that has had Uint8Array values mapped to base64.
 */
function replaceUint8ArrayWithBase64(
  source: Record<string, any> | any[],
): Record<string, any> {
  let sourceCopy = cloneDeep(source || {})
  if (u.isObj(source)) {
    Object.keys(sourceCopy).forEach((key) => {
      if (sourceCopy[key] instanceof Uint8Array) {
        sourceCopy[key] = store.level2SDK.utilServices.uint8ArrayToBase64(
          sourceCopy[key],
        )
      } else if (u.isObj(sourceCopy[key])) {
        sourceCopy[key] = replaceUint8ArrayWithBase64(sourceCopy[key])
      } else if (
        u.isArr(sourceCopy[key]) &&
        !(sourceCopy[key] instanceof Uint8Array)
      ) {
        sourceCopy[key] = sourceCopy[key].map((elem) =>
          replaceUint8ArrayWithBase64(elem),
        )
      }
    })
  } else if (u.isArr(source)) {
    // @ts-expect-error
    sourceCopy = source.map((elem) => replaceUint8ArrayWithBase64(elem))
  }
  return sourceCopy
}

function replaceVars({ vars, source }) {
  const withVals = populateObject({
    source,
    lookFor: '$',
    locations: [vars],
    skipIf: false,
  })
  return withVals
}
